```class Solution {
    public List<Integer> findSubstring(String s, String[] words) {
        List<Integer> res = new ArrayList<>();
        if (words.length == 0) return res;
        int wordLen = words[0].length();
        int wordNum = words.length;
        int totalLen = wordLen * wordNum;
        Map<String, Integer> map = new HashMap<>();
        for (String word : words) {
            map.put(word, map.getOrDefault(word, 0) + 1);
        }
        for (int i = 0; i <= s.length() - totalLen; i++) {
            Map<String, Integer> temp = new HashMap<>();
            for (int j = 0; j < wordNum; j++) {
                String sub = s.substring(i + j * wordLen, i + (j + 1) * wordLen);
                if (!map.containsKey(sub)) continue;
                temp.put(sub, temp.getOrDefault(sub, 0) + 1);
                if (temp.get(sub) > map.get(sub)) break;
            }
            if (temp.equals(map)) res.add(i);
        }
        return res;
    }
}```
